"use client";

import Link from "next/link";
import { CheckCircle2, Clock, Database, RotateCcw } from "lucide-react";
import type { AgentTrace, CheckReport } from "@/lib/types";

export function TraceClient({ initialTrace, report, reportId }: { initialTrace: AgentTrace[] | null; report: CheckReport | null; reportId: string }) {
  const trace = initialTrace ?? [];
  if (!report || trace.length === 0) {
    return (
      <main className="app-shell compact">
        <section className="panel empty-state">
          <h1>没有找到这份智能体轨迹</h1>
          <p>回到首页重新做一次投前体检，完成后这里会显示每个智能体的输入、输出和影响。</p>
          <Link className="primary-link" href="/" data-empty-cta="回到投前体检台">回到投前体检台</Link>
        </section>
      </main>
    );
  }
  return (
    <main className="app-shell" data-visual-lane="operational-dashboard / blueprint-lab 混合。" data-hero-composition="agent-audit-log" data-testid="screen-trace">
      <header className="topbar">
        <Link className="brand-lockup link-reset" href={`/result/${reportId}`}>
          <div className="brand-mark">体</div>
          <div>
            <h1>智能体轨迹</h1>
            <p>每个结论都能追到输入摘要、输出摘要和状态</p>
          </div>
        </Link>
        <div className="boundary-note">不展示完整隐私原文，只展示审计摘要</div>
      </header>
      <section className="trace-summary panel" data-testid="trace-report-summary">
        <div><span>目标岗位</span><b>{report?.targetRole ?? "未识别"}</b></div>
        <div><span>投递建议</span><b>{report?.trafficLightLabel ?? "暂无"}</b></div>
        <div><span>评分</span><b>{report?.score ?? "--"} 分</b></div>
        <div><span>报告版本</span><b>v{report?.version ?? 0}</b></div>
      </section>
      <section className="trace-grid" data-testid="agent-trace-timeline">
        {trace.map((item) => (
          <article className="panel trace-card" key={item.id} data-testid="agent-trace-node">
            <div className="trace-card-head">
              <span className="trace-order">{item.orderIndex}</span>
              <span className="status-pill green" data-testid="agent-trace-status"><CheckCircle2 size={14} />已完成</span>
            </div>
            <h2>{item.displayName}</h2>
            <p data-testid="agent-input-summary"><Database size={16} />{item.inputSummary}</p>
            <p data-testid="agent-output-summary"><RotateCcw size={16} />{item.outputSummary}</p>
            <p data-testid="agent-impact-summary"><CheckCircle2 size={16} />{item.impactSummary}</p>
            <small data-testid="agent-duration"><Clock size={14} />耗时 {item.durationMs} 毫秒</small>
          </article>
        ))}
      </section>
      <div className="trace-actions">
        <Link className="primary-link" href={`/result/${reportId}`}>返回体检结果</Link>
        <Link className="secondary-link" href={`/card/${reportId}`}>查看求职证据卡</Link>
      </div>
    </main>
  );
}
